        dateEl?.setProperties({ text: `${d.getMonth() + 1}/${d.getDate()}` });
      } else {
        rankEl?.setProperties({ text: `${i + 1}` });
        scoreEl?.setProperties({ text: '-' });
        levelEl?.setProperties({ text: '-' });
        modeEl?.setProperties({ text: '-' });
        dateEl?.setProperties({ text: '-' });
