const STORAGE_KEY = 'neon-pac-achievements';

export class AchievementManager {
  achievements: Achievement[] = [];
  private newUnlocks: Achievement[] = [];

  // Callback for UI notification
  onUnlock?: (achievement: Achievement) => void;

  constructor() {
    this.loadAchievements();
  }

  private loadAchievements(): void {
    const saved = this.loadFromStorage();
    this.achievements = ACHIEVEMENT_DEFS.map((def) => ({
      ...def,
      unlocked: saved.has(def.id),
      unlockedAt: saved.get(def.id),
    }));
  }

  private loadFromStorage(): Map<string, number> {
    const map = new Map<string, number>();
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const data = JSON.parse(raw) as Record<string, number>;
        for (const [k, v] of Object.entries(data)) {
          map.set(k, v);
        }
      }
    } catch { /* ignore */ }
    return map;
  }

  private saveToStorage(): void {
    try {
      const data: Record<string, number> = {};
      for (const a of this.achievements) {
        if (a.unlocked && a.unlockedAt) {
          data[a.id] = a.unlockedAt;
        }
      }
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    } catch { /* ignore */ }
  }

  unlock(id: string): boolean {
    const a = this.achievements.find((x) => x.id === id);
    if (!a || a.unlocked) return false;
    a.unlocked = true;
    a.unlockedAt = Date.now();
    this.newUnlocks.push(a);
    this.saveToStorage();
    this.onUnlock?.(a);
    return true;
  }

  popNewUnlock(): Achievement | undefined {
    return this.newUnlocks.shift();
  }

  hasNewUnlocks(): boolean {
    return this.newUnlocks.length > 0;
  }

  getUnlockedCount(): number {
    return this.achievements.filter((a) => a.unlocked).length;
  }

  getTotalCount(): number {
    return this.achievements.length;
  }

  getByCategory(cat: AchievementCategory): Achievement[] {
    return this.achievements.filter((a) => a.category === cat);
  }

  isUnlocked(id: string): boolean {
    return this.achievements.find((a) => a.id === id)?.unlocked ?? false;
  }

  // Get achievements as paginated list (8 per page)
  getPage(page: number, perPage = 8): { items: Achievement[]; totalPages: number } {
    const total = this.achievements.length;
    const totalPages = Math.ceil(total / perPage);
    const start = page * perPage;
    const items = this.achievements.slice(start, start + perPage);
    return { items, totalPages };
  }

  // Get unlocked achievements for display
  getUnlocked(): Achievement[] {
    return this.achievements.filter((a) => a.unlocked);
  }

  resetAll(): void {
    for (const a of this.achievements) {
      a.unlocked = false;
      a.unlockedAt = undefined;
    }
    this.newUnlocks = [];
    try { localStorage.removeItem(STORAGE_KEY); } catch { /* ignore */ }
  }
}

// === Neon Pac VR -- Audio Manager (procedural) ===

export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private muted = false;

  private getCtx(): AudioContext {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.value = 0.3;
      this.masterGain.connect(this.ctx.destination);
    }
    if (this.ctx.state === 'suspended') {
      this.ctx.resume();
    }
    return this.ctx;
  }

  private getMaster(): GainNode {
    this.getCtx();
    return this.masterGain!;
  }

  toggleMute(): boolean {
    this.muted = !this.muted;
    if (this.masterGain) {
      this.masterGain.gain.value = this.muted ? 0 : 0.3;
    }
    return this.muted;
  }

  playWaka(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'square';
    osc.frequency.setValueAtTime(440, t);
    osc.frequency.linearRampToValueAtTime(220, t + 0.06);
    gain.gain.setValueAtTime(0.15, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.08);
    osc.connect(gain);
    gain.connect(this.getMaster());
    osc.start(t);
    osc.stop(t + 0.1);
  }

  playPowerPellet(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    for (let i = 0; i < 4; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.08;
      osc.frequency.setValueAtTime(300 + i * 200, startTime);
      gain.gain.setValueAtTime(0.15, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.1);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.12);
    }
  }

  playGhostEat(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(800, t);
    osc.frequency.exponentialRampToValueAtTime(200, t + 0.3);
    gain.gain.setValueAtTime(0.2, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.35);
    osc.connect(gain);
    gain.connect(this.getMaster());
    osc.start(t);
    osc.stop(t + 0.4);
  }

  playDeath(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    for (let i = 0; i < 6; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.15;
      osc.frequency.setValueAtTime(600 - i * 80, startTime);
      osc.frequency.linearRampToValueAtTime(100, startTime + 0.12);
      gain.gain.setValueAtTime(0.15, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.14);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.16);
    }
  }

  playLevelComplete(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const notes = [523, 659, 784, 1047];
    for (let i = 0; i < notes.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.15;
      osc.frequency.setValueAtTime(notes[i], startTime);
      gain.gain.setValueAtTime(0.2, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.2);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.25);
    }
  }

  playGameStart(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const melody = [262, 330, 392, 523, 392, 330, 262];
    for (let i = 0; i < melody.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'square';
      const startTime = t + i * 0.12;
      osc.frequency.setValueAtTime(melody[i], startTime);
      gain.gain.setValueAtTime(0.1, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.1);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.12);
    }
  }

  playMenuSelect(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(660, t);
    gain.gain.setValueAtTime(0.1, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.08);
    osc.connect(gain);
    gain.connect(this.getMaster());
    osc.start(t);
    osc.stop(t + 0.1);
  }

  playFrightenedLoop(playing: boolean): void {
    // Simple one-shot siren blip for frightened state
    if (!playing) return;
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(200, t);
    osc.frequency.linearRampToValueAtTime(400, t + 0.2);
    osc.frequency.linearRampToValueAtTime(200, t + 0.4);
    gain.gain.setValueAtTime(0.06, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.4);
    osc.connect(gain);
    gain.connect(this.getMaster());
    osc.start(t);
    osc.stop(t + 0.45);
  }

  playAchievement(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const notes = [784, 988, 1175, 1319];
    for (let i = 0; i < notes.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.1;
      osc.frequency.setValueAtTime(notes[i], startTime);
      gain.gain.setValueAtTime(0.12, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.15);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.18);
    }
  }

  playExtraLife(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    // Triumphant ascending arpeggio
    const notes = [523, 659, 784, 1047, 1319];
    for (let i = 0; i < notes.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.08;
      osc.frequency.setValueAtTime(notes[i], startTime);
      gain.gain.setValueAtTime(0.2, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.2);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.25);
    }
    // Add a shimmer
    const shimmer = ctx.createOscillator();
    const shimmerGain = ctx.createGain();
    shimmer.type = 'triangle';
    shimmer.frequency.setValueAtTime(2000, t + 0.3);
    shimmer.frequency.linearRampToValueAtTime(4000, t + 0.6);
    shimmerGain.gain.setValueAtTime(0.06, t + 0.3);
    shimmerGain.gain.exponentialRampToValueAtTime(0.001, t + 0.7);
    shimmer.connect(shimmerGain);
    shimmerGain.connect(this.getMaster());
    shimmer.start(t + 0.3);
    shimmer.stop(t + 0.8);
  }
}

// === Neon Pac VR -- Particle ECS System ===

import { createSystem, Vector3 } from '@iwsdk/core';
import { ParticleManager } from './particles';
import { GameManager } from './game';
import { GameState, FRUIT_COLORS, FruitType, GHOST_COLORS, GhostName, CELL_SIZE } from './types';

export class ParticleSystem extends createSystem({}) {
  private particles!: ParticleManager;
  private game!: GameManager;
  private lastState: GameState = GameState.MENU;
  private lastScore = 0;
  private lastGhostsEaten = 0;
  private lastFruitsEaten = 0;

  setRefs(refs: { particles: ParticleManager; game: GameManager }): void {
    this.particles = refs.particles;
    this.game = refs.game;
  }

  update(delta: number, _time: number): void {
    if (!this.particles || !this.game) return;

    this.particles.update(delta);

    const state = this.game.state;

    // Detect ghost eaten
    const totalGhosts = this.game.statsManager.stats.totalGhostsEaten;
    if (totalGhosts > this.lastGhostsEaten) {
      this.lastGhostsEaten = totalGhosts;
      // Find the ghost that was just eaten
      for (const ghost of this.game.ghosts) {
        if (ghost.mode === 'eaten' as any) {
          const pos = ghost.mesh.position.clone();
          pos.y += 0.03;
          const color = ghost.originalColor;
          this.particles.ghostEatEffect(pos, color);
          break;
        }
      }
    }

    // Detect fruit eaten
    const totalFruits = this.game.statsManager.stats.totalFruitsEaten;
    if (totalFruits > this.lastFruitsEaten) {
      this.lastFruitsEaten = totalFruits;
      const pos = this.game.pacMesh.position.clone();
      pos.y += 0.03;
      this.particles.fruitEffect(pos, 0x44ff44);
    }

    // Detect state changes
    if (state !== this.lastState) {
      if (state === GameState.DYING) {
        const pos = this.game.pacMesh.position.clone();
        this.particles.deathEffect(pos);
      }
      if (state === GameState.LEVEL_COMPLETE) {
        const pos = this.game.pacMesh.position.clone();
        pos.y += 0.1;
        this.particles.levelCompleteEffect(pos);
      }
      this.lastState = state;
    }

    this.lastScore = this.game.score;
  }
}

