// === Neon Pac VR -- Stats Manager ===

export interface GameStats {
  totalGamesPlayed: number;
  totalScore: number;
  highScore: number;
  totalDotsEaten: number;
  totalPowerPelletsUsed: number;
  totalGhostsEaten: number;
  totalFruitsEaten: number;
  totalDeaths: number;
  totalLevelsCleared: number;
  highestLevel: number;
  totalTimePlayed: number; // seconds
  longestGameTime: number;
  bestLevelTime: number; // fastest level clear
  quadKills: number;
  tunnelUses: number;
  fruitsEatenByType: Record<string, number>;
  ghostsEatenByName: Record<string, number>;
  modesPlayed: Set<string>;
  consecutiveLevelsNoDeath: number;
  bestConsecutiveLevelsNoDeath: number;
}

const STORAGE_KEY = 'neon-pac-stats';

export class StatsManager {
  stats: GameStats;

  // Per-game tracking (reset each game)
  currentGameTime = 0;
  currentLevelTime = 0;
  currentLevelDeaths = 0;
  currentGameGhostsEaten = 0;
  currentGameFruitsEaten = 0;
  currentGameTunnelUses = 0;
  currentGameQuadKills = 0;
  currentGamePowerPelletsUsed = 0;
  currentGameGhostNames = new Set<string>();
  currentGameScore = 0;
  currentLevelPowerUsed = false;
  currentConsecutiveNoDeath = 0;
  currentFruitTypes = new Set<string>();

  constructor() {
    this.stats = this.load();
  }

  private load(): GameStats {
    const defaults: GameStats = {
      totalGamesPlayed: 0,
      totalScore: 0,
      highScore: 0,
      totalDotsEaten: 0,
      totalPowerPelletsUsed: 0,
      totalGhostsEaten: 0,
      totalFruitsEaten: 0,
      totalDeaths: 0,
      totalLevelsCleared: 0,
      highestLevel: 1,
      totalTimePlayed: 0,
      longestGameTime: 0,
      bestLevelTime: Infinity,
      quadKills: 0,
      tunnelUses: 0,
      fruitsEatenByType: {},
      ghostsEatenByName: {},
      modesPlayed: new Set<string>(),
      consecutiveLevelsNoDeath: 0,
      bestConsecutiveLevelsNoDeath: 0,
    };

    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const data = JSON.parse(raw);
        return {
          ...defaults,
          ...data,
          modesPlayed: new Set(data.modesPlayed ?? []),
        };
      }
    } catch { /* ignore */ }
    return defaults;
  }

  save(): void {
    try {
      const data = {
        ...this.stats,
        modesPlayed: Array.from(this.stats.modesPlayed),
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    } catch { /* ignore */ }
  }

  startGame(mode: string): void {
    this.stats.totalGamesPlayed++;
    this.stats.modesPlayed.add(mode);
    this.currentGameTime = 0;
    this.currentLevelTime = 0;
    this.currentLevelDeaths = 0;
    this.currentGameGhostsEaten = 0;
    this.currentGameFruitsEaten = 0;
    this.currentGameTunnelUses = 0;
    this.currentGameQuadKills = 0;
    this.currentGamePowerPelletsUsed = 0;
    this.currentGameGhostNames.clear();
    this.currentGameScore = 0;
    this.currentLevelPowerUsed = false;
    this.currentConsecutiveNoDeath = 0;
    this.currentFruitTypes.clear();
    this.save();
  }

  recordDotEaten(): void {
    this.stats.totalDotsEaten++;
  }

  recordPowerPellet(): void {
    this.stats.totalPowerPelletsUsed++;
    this.currentGamePowerPelletsUsed++;
    this.currentLevelPowerUsed = true;
  }

  recordGhostEaten(ghostName: string, chainCount: number): void {
    this.stats.totalGhostsEaten++;
    this.currentGameGhostsEaten++;
    this.currentGameGhostNames.add(ghostName);
    this.stats.ghostsEatenByName[ghostName] = (this.stats.ghostsEatenByName[ghostName] ?? 0) + 1;
    if (chainCount >= 4) {
      this.stats.quadKills++;
      this.currentGameQuadKills++;
    }
  }

  recordFruitEaten(fruitType: string): void {
    this.stats.totalFruitsEaten++;
    this.currentGameFruitsEaten++;
    this.currentFruitTypes.add(fruitType);
    this.stats.fruitsEatenByType[fruitType] = (this.stats.fruitsEatenByType[fruitType] ?? 0) + 1;
  }

  recordDeath(): void {
    this.stats.totalDeaths++;
    this.currentLevelDeaths++;
    this.currentConsecutiveNoDeath = 0;
  }

  recordTunnelUse(): void {
    this.stats.tunnelUses++;
    this.currentGameTunnelUses++;
  }

  recordLevelClear(levelTime: number): void {
    this.stats.totalLevelsCleared++;
    if (levelTime < this.stats.bestLevelTime) {
      this.stats.bestLevelTime = levelTime;
    }
    if (this.currentLevelDeaths === 0) {
      this.currentConsecutiveNoDeath++;
      if (this.currentConsecutiveNoDeath > this.stats.bestConsecutiveLevelsNoDeath) {
        this.stats.bestConsecutiveLevelsNoDeath = this.currentConsecutiveNoDeath;
      }
    }
    this.currentLevelTime = 0;
    this.currentLevelDeaths = 0;
    this.currentLevelPowerUsed = false;
    this.save();
  }

  recordGameEnd(score: number, level: number): void {
    this.currentGameScore = score;
    this.stats.totalScore += score;
    if (score > this.stats.highScore) {
      this.stats.highScore = score;
    }
    if (level > this.stats.highestLevel) {
      this.stats.highestLevel = level;
    }
    if (this.currentGameTime > this.stats.longestGameTime) {
      this.stats.longestGameTime = this.currentGameTime;
    }
    this.stats.totalTimePlayed += this.currentGameTime;
    this.save();
  }

  updateTime(delta: number): void {
    this.currentGameTime += delta;
    this.currentLevelTime += delta;
  }

  getFormattedTime(seconds: number): string {
    const m = Math.floor(seconds / 60);
    const s = Math.floor(seconds % 60);
    return `${m}:${s.toString().padStart(2, '0')}`;
  }

  reset(): void {
    try { localStorage.removeItem(STORAGE_KEY); } catch { /* ignore */ }
    this.stats = this.load();
  }
}

// === Neon Pac VR -- Leaderboard Manager ===

export interface LeaderboardEntry {
  score: number;
  level: number;
  mode: string;
  difficulty: string;
  date: number; // timestamp
}

const STORAGE_KEY = 'neon-pac-leaderboard';
const MAX_ENTRIES = 50;

export class LeaderboardManager {
  entries: LeaderboardEntry[] = [];

  constructor() {
    this.load();
  }

  private load(): void {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        this.entries = JSON.parse(raw) as LeaderboardEntry[];
      }
    } catch { /* ignore */ }
  }

  private save(): void {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(this.entries));
    } catch { /* ignore */ }
  }

  addEntry(score: number, level: number, mode: string, difficulty: string): void {
    if (score <= 0) return;
    this.entries.push({
      score,
      level,
      mode,
      difficulty,
      date: Date.now(),
    });
    // Sort by score descending
    this.entries.sort((a, b) => b.score - a.score);
    // Keep only top entries
    if (this.entries.length > MAX_ENTRIES) {
      this.entries = this.entries.slice(0, MAX_ENTRIES);
    }
    this.save();
  }

  getTopScores(count = 10, modeFilter?: string): LeaderboardEntry[] {
    let filtered = this.entries;
    if (modeFilter && modeFilter !== 'all') {
      filtered = filtered.filter((e) => e.mode === modeFilter);
    }
    return filtered.slice(0, count);
  }

  getRank(score: number, modeFilter?: string): number {
    let filtered = this.entries;
    if (modeFilter && modeFilter !== 'all') {
      filtered = filtered.filter((e) => e.mode === modeFilter);
    }
    const rank = filtered.filter((e) => e.score > score).length + 1;
    return rank;
  }

  getPersonalBest(mode?: string): number {
    let filtered = this.entries;
    if (mode) {
      filtered = filtered.filter((e) => e.mode === mode);
    }
    if (filtered.length === 0) return 0;
    return filtered[0].score;
  }

  reset(): void {
    this.entries = [];
    try { localStorage.removeItem(STORAGE_KEY); } catch { /* ignore */ }
  }
}

// === Neon Pac VR -- Particle Effects System ===

import {
  Group,
  Mesh,
  SphereGeometry,
  MeshBasicMaterial,
  Color,
  Vector3,
} from '@iwsdk/core';

interface Particle {
  mesh: Mesh;
  velocity: Vector3;
  life: number;
  maxLife: number;
}

export class ParticleManager {
  private particles: Particle[] = [];
  private group: Group;
  private geo: SphereGeometry;
  private pool: Mesh[] = [];

  constructor(parent: Group) {
    this.group = new Group();
    parent.add(this.group);
    this.geo = new SphereGeometry(0.008, 4, 3);
  }

  // Burst of particles at position with given color
  burst(position: Vector3, color: number, count = 12, speed = 0.5): void {
    for (let i = 0; i < count; i++) {
      const mesh = this.getMesh(color);
      mesh.position.copy(position);
      mesh.visible = true;

      const angle = (Math.PI * 2 * i) / count + (Math.random() - 0.5) * 0.5;
      const elevation = (Math.random() - 0.3) * Math.PI;
      const spd = speed * (0.5 + Math.random() * 0.5);

      const velocity = new Vector3(
        Math.cos(angle) * Math.cos(elevation) * spd,
        Math.sin(elevation) * spd * 0.5 + 0.2,
        Math.sin(angle) * Math.cos(elevation) * spd,
      );

      const life = 0.5 + Math.random() * 0.5;
      this.particles.push({ mesh, velocity, life, maxLife: life });
    }
  }

  // Score popup effect — spray upward
  scorePopup(position: Vector3, color: number): void {
    this.burst(position, color, 8, 0.3);
  }

  // Ghost eat effect — big burst
  ghostEatEffect(position: Vector3, ghostColor: number): void {
    this.burst(position, ghostColor, 20, 0.8);
    this.burst(position, 0xffffff, 6, 0.4);
  }

  // Death effect
  deathEffect(position: Vector3): void {
    this.burst(position, 0xffff00, 24, 0.6);
    this.burst(position, 0xff4400, 12, 0.4);
  }

  // Level complete celebration
  levelCompleteEffect(position: Vector3): void {
    const colors = [0xff0000, 0x00ff00, 0x0066ff, 0xffff00, 0xff00ff, 0x00ffff];
    for (const c of colors) {
      this.burst(position, c, 6, 0.7);
    }
  }

  // Fruit eat effect
  fruitEffect(position: Vector3, fruitColor: number): void {
    this.burst(position, fruitColor, 16, 0.6);
    this.burst(position, 0xffffff, 4, 0.3);
  }

  update(delta: number): void {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= delta;

      if (p.life <= 0) {
        p.mesh.visible = false;
        this.pool.push(p.mesh);
        this.particles.splice(i, 1);
        continue;
      }

      // Move
      p.mesh.position.x += p.velocity.x * delta;
      p.mesh.position.y += p.velocity.y * delta;
      p.mesh.position.z += p.velocity.z * delta;

      // Gravity
      p.velocity.y -= 1.5 * delta;

      // Fade out
      const t = p.life / p.maxLife;
      const scale = t * 1.5;
      p.mesh.scale.setScalar(scale);
      const mat = p.mesh.material as MeshBasicMaterial;
      mat.opacity = t;
    }
  }

  private getMesh(color: number): Mesh {
    if (this.pool.length > 0) {
      const mesh = this.pool.pop()!;
      (mesh.material as MeshBasicMaterial).color.setHex(color);
      (mesh.material as MeshBasicMaterial).opacity = 1;
      mesh.scale.setScalar(1);
      return mesh;
    }

    const mat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 1,
    });
    const mesh = new Mesh(this.geo, mat);
    this.group.add(mesh);
    return mesh;
  }
}

